"use strict";
import {
    deleteUserService,
    getUserService,
    getUsersService,
    updateUserService,
} from "../services/user.service.js";
import {
    userBodyValidation,
    userQueryValidation,
} from "../validations/user.validation.js";
import {
    handleErrorClient,
    handleErrorServer,
    handleSuccess,
} from "../handlers/responseHandlers.js";

export async function getUser(req, res) {
    try {
        const { rut, id, email } = req.query;

        const { error } = userQueryValidation.validate({ rut, id, email });

        if (error) return handleErrorClient(res, 400, error.message);

        const [user, errorUser] = await getUserService({ rut, id, email });

        if (errorUser) return handleErrorClient(res, 404, errorUser);

        handleSuccess(res, 200, "Usuario encontrado", user);
    } catch (error) {
        handleErrorServer(res, 500, error.message);
    }
}

export async function getUsers(req, res) {
    try {
        const [users, errorUsers] = await getUsersService();

        if (errorUsers) return handleErrorClient(res, 404, errorUsers);

        users.length === 0
            ? handleSuccess(res, 204)
            : handleSuccess(res, 200, "Usuarios encontrados", users);
    } catch (error) {
        handleErrorServer(
            res,
            500,
            error.message,
        );
    }
}

export async function updateUser(req, res) {
    try {
        const { rut, id, email } = req.query;
        const { body } = req;

        console.log('=== UPDATE USER REQUEST ===');
        console.log('Query params:', { rut, id, email });
        console.log('Body recibido:', JSON.stringify(body, null, 2));

        const { error: queryError } = userQueryValidation.validate({
            rut,
            id,
            email,
        });

        if (queryError) {
            console.log('Error de validación en query:', queryError.details);
            return handleErrorClient(
                res,
                400,
                "Error de validación en la consulta",
                queryError.message,
            );
        }

        console.log('Query validation exitosa');

        const { error: bodyError } = userBodyValidation.validate(body);

        if (bodyError) {
            console.log('Error de validación en body:', bodyError.details);
            return handleErrorClient(
                res,
                400,
                "Error de validación en los datos enviados",
                bodyError.message,
            );
        }

        console.log('Body validation exitosa, llamando a updateUserService...');

        const [user, userError] = await updateUserService({ rut, id, email }, body);

        if (userError) {
            console.log('Error en updateUserService:', userError);
            return handleErrorClient(res, 400, "Error modificando al usuario", userError);
        }

        console.log('Usuario actualizado exitosamente:', user);
        handleSuccess(res, 200, "Usuario modificado correctamente", user);
    } catch (error) {
        console.error('Error en updateUser controller:', error);
        handleErrorServer(res, 500, error.message);
    }
}

export async function deleteUser(req, res) {
    try {
        const { rut, id, email } = req.query;

        const { error: queryError } = userQueryValidation.validate({
            rut,
            id,
            email,
        });

        if (queryError) {
            return handleErrorClient(
                res,
                400,
                "Error de validación en la consulta",
                queryError.message,
            );
        }

        const [userDelete, errorUserDelete] = await deleteUserService({
            rut,
            id,
            email,
        });

        if (errorUserDelete) return handleErrorClient(res, 404, "Error eliminado al usuario", errorUserDelete);

        handleSuccess(res, 200, "Usuario eliminado correctamente", userDelete);
    } catch (error) {
        handleErrorServer(res, 500, error.message);
    }
}

export const transformUserToNewStructure = (user) => {
    if (!user.nombreCompleto) {
        return {
            primerNombre: user.primerNombre || "",
            segundoNombre: user.segundoNombre || "",
            apellidoPaterno: user.apellidoPaterno || "",
            apellidoMaterno: user.apellidoMaterno || ""
        };
    }

    const nombreCompleto = user.nombreCompleto.trim();
    const partes = nombreCompleto.split(" ").filter(parte => parte.length > 0);

    if (partes.length === 0) {
        return {
            primerNombre: "",
            segundoNombre: "",
            apellidoPaterno: "",
            apellidoMaterno: ""
        };
    }

    if (partes.length === 1) {
        return {
            primerNombre: partes[0],
            segundoNombre: "",
            apellidoPaterno: "",
            apellidoMaterno: ""
        };
    }

    if (partes.length === 2) {
        return {
            primerNombre: partes[0],
            segundoNombre: "",
            apellidoPaterno: partes[1],
            apellidoMaterno: ""
        };
    }

    if (partes.length === 3) {
        return {
            primerNombre: partes[0],
            segundoNombre: "",
            apellidoPaterno: partes[1],
            apellidoMaterno: partes[2]
        };
    }

    if (partes.length === 4) {
        return {
            primerNombre: partes[0],
            segundoNombre: partes[1],
            apellidoPaterno: partes[2],
            apellidoMaterno: partes[3]
        };
    }

    if (partes.length >= 5) {
        const nombres = partes.slice(0, -2);
        const apellidos = partes.slice(-2);
        
        return {
            primerNombre: nombres[0],
            segundoNombre: nombres.slice(1).join(" "),
            apellidoPaterno: apellidos[0],
            apellidoMaterno: apellidos[1]
        };
    }

    return {
        primerNombre: "",
        segundoNombre: "",
        apellidoPaterno: "",
        apellidoMaterno: ""
    };
};

export const getNombreCompleto = (user) => {
    if (!user || !user.primerNombre) return "";
    
    const parts = [
        user.primerNombre,
        user.segundoNombre,
        user.apellidoPaterno,
        user.apellidoMaterno
    ].filter(Boolean);
    
    return parts.join(" ");
};

export const getNombreCorto = (user) => {
    if (!user?.primerNombre) return "";
    
    return user.primerNombre.trim().split(' ')[0];
};

export const getNombreFormal = (user) => {
    if (!user || !user.primerNombre) return "";
    
    const parts = [user.primerNombre, user.apellidoPaterno].filter(Boolean);
    return parts.join(" ");
};

export const getNombres = (user) => {
    if (!user || !user.primerNombre) return "";
    
    const parts = [user.primerNombre, user.segundoNombre].filter(Boolean);
    return parts.join(" ");
};

export const getApellidos = (user) => {
    if (!user || !user.apellidoPaterno) return "";
    
    const parts = [user.apellidoPaterno, user.apellidoMaterno].filter(Boolean);
    return parts.join(" ");
};

export const getIniciales = (user) => {
    if (!user || !user.primerNombre) return "";
    
    const inicial1 = user.primerNombre.charAt(0).toUpperCase();
    const inicial2 = user.apellidoPaterno ? user.apellidoPaterno.charAt(0).toUpperCase() : "";
    
    return inicial1 + inicial2;
};

import { Router } from "express";
import {
    crearDireccionController,
    obtenerDireccionesController,
    obtenerDireccionController,
    actualizarDireccionController,
    eliminarDireccionController,
    establecerPrincipalController
} from "../controllers/direccion.controller.js";
import { validateSchema, validateParams } from "../middlewares/validateSchema.js";
import { direccionSchema, direccionUpdateSchema, direccionIdSchema } from "../validations/direccion.validation.js";
import { authenticateJwt } from "../middlewares/authentication.middleware.js";

const router = Router();

router
    // Crear nueva dirección - requiere autenticación
    .post("/", 
        authenticateJwt, 
        validateSchema(direccionSchema), 
        crearDireccionController
    )
    // Obtener todas las direcciones del usuario - requiere autenticación
    .get("/", 
        authenticateJwt, 
        obtenerDireccionesController
    )
    // Obtener dirección específica por ID - requiere autenticación
    .get("/:id", 
        authenticateJwt, 
        validateParams(direccionIdSchema), 
        obtenerDireccionController
    )
    // Actualizar dirección - requiere autenticación
    .put("/:id", 
        authenticateJwt, 
        validateParams(direccionIdSchema),
        validateSchema(direccionUpdateSchema), 
        actualizarDireccionController
    )
    // Eliminar dirección - requiere autenticación (solo valida ID)
    .delete("/:id", 
        authenticateJwt, 
        validateParams(direccionIdSchema), 
        eliminarDireccionController
    )
    // Establecer como dirección principal - requiere autenticación (solo valida ID)
    .patch("/:id/principal", 
        authenticateJwt, 
        validateParams(direccionIdSchema), 
        establecerPrincipalController
    );

export default router;

import { Router } from "express";
import {
    actualizarProductoController,
    buscarProductosController,
    crearProductoController,
    eliminarProductoController,
    subirImagenProductoController,
    obtenerSugerenciasBusquedaController,
} from "../controllers/producto.controller.js";
import { validateSchema } from "../middlewares/validateSchema.js";
import { validateProductoMultipart } from "../middlewares/validateProductoMultipart.js";
import { validateProductUpdateMultipart } from "../middlewares/validateProductUpdateMultipart.js";
import { productSchema, productUpdateSchema } from "../validations/producto.validation.js";
import { authenticateJwt } from "../middlewares/authentication.middleware.js";
import { isAdmin } from "../middlewares/authorization.middleware.js";

import uploadProducto from "../middlewares/uploadProducto.middleware.js";

const router = Router();

router
    .post("/", 
        authenticateJwt, 
        isAdmin, 
        uploadProducto.single("imagen"), 
        validateProductoMultipart, 
        crearProductoController
    )
    .get("/", buscarProductosController)
    .get("/sugerencias", obtenerSugerenciasBusquedaController)
    .put("/:id", 
        authenticateJwt, 
        isAdmin, 
        uploadProducto.single("imagen"),
        validateProductUpdateMultipart,
        validateSchema(productUpdateSchema), 
        actualizarProductoController
    )
    .delete("/:id", authenticateJwt, isAdmin, eliminarProductoController);

router.post(
    "/:id/imagen",
    authenticateJwt,
    isAdmin,
    uploadProducto.single("imagen"),
    subirImagenProductoController
);

router.put(
    "/:id/imagen",
    authenticateJwt,
    isAdmin,
    uploadProducto.single("imagen"),
    subirImagenProductoController
);

export default router;

"use strict";
